import { useTheme } from '../../context/theme';
import { useUserPreferences } from '../../context/userPreferences';
import { LANGUAGES } from '../../i18n/translations';
import { formatDate } from '../utils/date-utils';

interface MovieProfileProps {
	pictureUrl: string;
	releaseDate: string;
	ratingPosition?: number;
	title: string;
}

export function MovieProfile({ pictureUrl, ratingPosition, releaseDate, title }: MovieProfileProps) {
	const { theme } = useTheme();
	const { language } = useUserPreferences();
	return (
		<div
			className={`${theme.lighterThemeBgClassName} ${theme.themeTextClassName} hover:${theme.movieProfileHoverTheme} hover:scale-125 transition-transform rounded-lg flex flex-col text-center font-semibold p-4 self-auto align-middle`}
		>
			<img className="mx-auto h-80 w-60 rounded-md" src={pictureUrl} alt={`Banner do Filme${title}`} />
			<p>{title}</p>
			<p className="font-nunito font-light"> {LANGUAGES[language].releaseDate} {formatDate(language, releaseDate)}</p>
		</div>
	);
}
